public class Student { private String studentId; private String studentName; private String grade; public Student(String id, String name, String grade) { studentId=id; studentName=name; this.grade=grade; } public String getStudentId() { return studentId; } public String getStudentName() { return studentName; } public String getGrade() { return grade; } public void setStudentName(String n) { studentName=n; } public void setGrade(String g) { grade=g; } }